     3→import provided.utils.valueGenerator.ISineMaker;
     4→
     5→/**
     6→ * A utility class that can be used to create smoothly varying sinusoidal
     7→ * numerical data.
     8→ * Note that this is not a singleton class nor does it have static methods as
     9→ * its behavior depends on the minimum, maximum and delta values given to 
    10→ * its constructor.
    11→ */
    12→public class SineMaker implements ISineMaker {
    13→	/**
    14→	 * The midpoint of the min and max values.
    15→	 */
    16→	private double _mid;
    17→	/**
    18→	 * The amplitude of the sinusoidal output
    19→	 */
    20→	private double _ampl;
    21→	/**
    22→	 * The amount that _theta is incremented each time, in radians.
    23→	 */
    24→	private double _delta;
    25→	/**
    26→	 * The current angle used to generate the current
    27→	 * sinusoidal value.  Initialized to produce the minimum value.
    28→	 */
    29→	private double _theta = -Math.PI / 2.0;
    30→
    31→	/**
    32→	 * The constructor takes several values to control the object's behavior.
    33→	 * @param min The minimum and initial value to produce.
    34→	 * @param max The maximum value to produce.
    35→	 * @param delta The amount in radians that the generating angle is incremented each time
    36→	 * */
    37→	public SineMaker(double min, double max, double delta) {
    38→		_mid = (max + min) / 2.0;
    39→		_ampl = (max - min) / 2.0;
    40→		_delta = delta;
    41→	}
    42→
    43→	/* (non-Javadoc)
    44→	 * @see provided.utils.valueGenerator.ISineMaker#getDblVal()
    45→	 */
    46→	@Override
    47→	public double getDblVal() {
    48→		double result = _mid + _ampl * Math.sin(_theta);
    49→		_theta += _delta; // shorthand for _theta = _theta + _delta
    50→		return result;
    51→	}
    52→
    53→	/* (non-Javadoc)
    54→	 * @see provided.utils.valueGenerator.ISineMaker#getIntVal()
    55→	 */
    56→	@Override
    57→	public int getIntVal() {
    58→		return (int) Math.round(getDblVal());
    59→	}
    60→}

